WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")} 

var P45_Date_Head_Office = '{!Contact.P45_Date_by_Head_Office__c}'; 
var P45_Requested = '{!Contact.P45_Requested__c}'; 

var childrecord = sforce.connection.query("SELECT ID,IP_Status__c FROM ts2__Certification__c where (RecordType.Name='TOE' OR RecordType.Name='New Starter Declaration Form') AND ts2__Contact__c ='{!Contact.Id}'" ); 

var precord= sforce.connection.query("SELECT ID,IP_Status__c,IP_NewStarterTaxStatus__c,IP_StudentLoan__c, P45_Date_by_Head_Office__c, P45_Requested__c,P45_Initiated__c, Reason_for_P45_Internal__c, Reason_for_Leaving1__c,Date_P45_Requested__c FROM IP_PayProfile__c where RecordType.Name = 'PAYE' AND IP_Status__c='Inactive' AND IP_Candidate__c ='{!Contact.Id}'" ); 

var payrecord = sforce.connection.query("SELECT ID,IP_Status__c FROM IP_PayProfile__c where (RecordType.Name = 'LTD' OR RecordType.Name = 'Umbrella') AND IP_Candidate__c ='{!Contact.Id}' AND IP_Status__c='Inactive'"); 

var paylist = payrecord.getArray("records"); 
var plist = precord.getArray("records"); 
var updatepRecord = new Array(); 
var updateconRecord = new Array(); 

var records = childrecord.getArray("records"); 
var updatecertRecord = new Array(); 


if(P45_Date_Head_Office !='') 
{ 

var c= new sforce.SObject("Contact"); 
c.id="{!Contact.Id}"; 
c.P45_Requested__c = false; 
c.Reason_for_Leaving1__c=null; 
c.P45_Date_by_Head_Office__c=null; 
c.IP_WorkerLeavingDate__c=null; 
c.Reason_for_P45__c=null; 
c.IP_WorkerStartDate__c=null; 
c.Student__c=false; 
c.TOE_Completed__c=false; 
c.New_Starter_Form__c=false; 
c.Sync_Pay_Profile__c = false;
c.Sync_Pay_Profile2__c = false;

updateconRecord.push(c);
for (i=0; i < records.length ; i++) 
{ 
var child = records[i]; 
child.IP_Status__c = 'Lapsed'; 


updatecertRecord.push(child); 

} 

childrecord = sforce.connection.update(updatecertRecord); 

if(paylist.length>0) 
{ 

var win = window.open('/apex/Payprofileactive?id={! Contact.Id}', '_blank', 'height=550,width=800,resizable=yes,scrollbars=yes,toolbar=n‌​o,menubar=no'); 


} 
else if(paylist.length ==0 && plist.length>0) 
{ 
for (i=0; i < plist.length ; i++) 
{ 
var child = plist[i]; 
child.IP_Status__c = 'Active'; 
child.P45_Date_by_Head_Office__c=null; 
child.P45_Requested__c=false; 
child.Reason_for_P45_Internal__c=null; 
child.Reason_for_Leaving1__c = null; 
child.P45_Initiated__c=false; 
child.IP_NewStarterTaxStatus__c = null;
child.IP_StudentLoan__c = null;
child.Date_P45_Requested__c = null;
child.IP_PassToTempest__c=false;
child.IP_LastPassedToTempest__c=null;

updatepRecord.push(child); 

} 

precord = sforce.connection.update(updatepRecord); 
//alert('precord '+precord ); 
//alert('test '+c); 
var results= sforce.connection.update(updateconRecord); 
//alert('results '+results); 
alert('Candiate Reinstated'); 
location.reload(true); 
} 
else{ 
alert('There is no Inactive Pay Profile associated to this Contact'); } 
} 
else 
{ 
alert('You have not requested P45 OR you have not issued P45'); 
}
